  ('judicial-4d3895b1-moex-00143', 'judicial-4d3895b1', 'judicial-4d3895b1-moex-111-f9fb6a06', 'sub-judicial-4d3895b1-06', NULL, 'essay', '中翻英：請將下列中文段落譯成英文：（30 分）
威勒米爾（Willeumier）博士從事大腦方面的研究，非常擅長處理精密的
大腦影像。她曾根據看過的病例和腦部影像資料中得知，當人們改變生
活習慣、並加以保持，就能大幅改善大腦的健康狀態。威勒米爾博士指
出，人們從 40 歲開始，平均每 10 年大腦容量減少 5%。如果人們可以
開始保護大腦，讓很多生活細節成為習慣，就有可能減緩大腦容量減少
的幅度。人們可以透過一些日常生活習慣，來活化自己的大腦，如快走
10 分鐘、吃黑巧克力、坐直伸展背肌、練習使用左手、學習新單字、在
腦中預演當日行程、放空10 分鐘及用香味消除壓力。這些活動都對活化
大腦極有幫助。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:28+00:00", "source_pdf_sha1": "8b36f6f41c40", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "英文", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公證人"}'::jsonb, NULL),
